const answer = $input.first().json.answer || '_Nessuna risposta trovata._';
const sources = $input.first().json.sources || [];

// Timestamp italiano
const now = new Date().toLocaleString('it-IT', { timeZone: 'Europe/Rome' });

// Corpo risposta
let md = `## Risposta\n\n${answer}`;

// Sezione fonti
if (sources.length > 0) {
  md += '\n\n---\n\n### Fonti consultate\n\n';
  sources.forEach((s, i) => {
    const filename = s.split('/').pop();
    md += `${i + 1}. \`${filename}\`\n   _percorso: ${s}_\n`;
  });
} else {
  md += '\n\n---\n\n> Nessuna fonte specifica individuata per questa risposta.';
}

// Footer
md += `\n\n---\n_Risposta generata il ${now}_`;

return [{ json: { output: md } }];
